/**
 * StatusBar Component Tests
 * Tests for the migrated StatusBar component using the new architecture
 */
import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { render, screen, waitFor } from '@testing-library/svelte';
import StatusBar from './StatusBar.svelte';

// Store state that we'll manipulate in tests
let crosshairStoreState = {
  worldCoord: [0, 0, 0],
  voxelCoord: [0, 0, 0],
  visible: true,
  setWorldCoord: vi.fn((coord: number[]) => {
    crosshairStoreState.worldCoord = coord;
  }),
  setVoxelCoord: vi.fn((coord: number[]) => {
    crosshairStoreState.voxelCoord = coord;
  })
};

let layerStoreState = {
  layers: new Map(),
  activeLayerId: null as string | null,
  getLayer: vi.fn((id: string) => layerStoreState.layers.get(id))
};

// Mock services
const mockCrosshairService = {
  getWorldCoord: vi.fn(() => crosshairStoreState.worldCoord),
  setWorldCoord: vi.fn((coord: number[]) => {
    crosshairStoreState.worldCoord = coord;
  })
};

const mockLayerService = {
  getActiveLayer: vi.fn(() => {
    return layerStoreState.activeLayerId 
      ? layerStoreState.layers.get(layerStoreState.activeLayerId) 
      : null;
  }),
  sampleWorldCoordinate: vi.fn()
};

const mockEventBus = {
  on: vi.fn(() => () => {}),
  off: vi.fn(),
  emit: vi.fn(),
  getListenerCount: vi.fn(() => 0)
};

const mockApi = {
  sample_world_coordinate: vi.fn()
};

// Mock modules
vi.mock('$lib/di/Container', () => ({
  getService: vi.fn(async (name: string) => {
    switch (name) {
      case 'crosshairService':
        return mockCrosshairService;
      case 'layerService':
        return mockLayerService;
      case 'eventBus':
        return mockEventBus;
      case 'api':
        return mockApi;
      default:
        return {};
    }
  })
}));

vi.mock('$lib/stores/crosshairSlice', () => ({
  useCrosshairStore: {
    getState: () => crosshairStoreState,
    subscribe: (listener: Function) => {
      listener(crosshairStoreState, crosshairStoreState);
      return () => {};
    }
  }
}));

vi.mock('$lib/stores/layerStore', () => ({
  useLayerStore: {
    getState: () => layerStoreState,
    subscribe: (listener: Function) => {
      listener(layerStoreState, layerStoreState);
      return () => {};
    }
  }
}));

vi.mock('$lib/stores/zustandBridge', () => ({
  zustandToReadable: (store: any) => ({
    subscribe: (run: Function) => {
      return store.subscribe((state: any) => run(state));
    }
  })
}));

describe('StatusBar', () => {
  beforeEach(() => {
    // Reset store states
    crosshairStoreState.worldCoord = [0, 0, 0];
    crosshairStoreState.voxelCoord = [0, 0, 0];
    crosshairStoreState.visible = true;

    layerStoreState.layers = new Map();
    layerStoreState.activeLayerId = null;

    // Clear all mocks
    vi.clearAllMocks();

    // Reset event bus mock to track listener counts
    let listenerCounts: Record<string, number> = {};
    mockEventBus.on.mockImplementation((event: string, handler: Function) => {
      listenerCounts[event] = (listenerCounts[event] || 0) + 1;
      return () => {
        listenerCounts[event] = Math.max(0, (listenerCounts[event] || 0) - 1);
      };
    });
    mockEventBus.getListenerCount.mockImplementation((event: string) => listenerCounts[event] || 0);
  });

  it('should render initial state', async () => {
    render(StatusBar);
    await waitFor(() => {});

    // Check basic elements are present
    expect(screen.getByRole('status')).toBeInTheDocument();
    expect(screen.getByText(/World:/)).toBeInTheDocument();
    expect(screen.getByText(/Voxel:/)).toBeInTheDocument();
  });

  it('should display crosshair coordinates', async () => {
    // Set up crosshair state
    crosshairStoreState.worldCoord = [10.5, 20.3, 30.7];
    crosshairStoreState.voxelCoord = [50, 60, 70];
    crosshairStoreState.visible = true;

    render(StatusBar);
    await waitFor(() => {});

    // Check world coordinates
    expect(screen.getByText(/10\.5/)).toBeInTheDocument();
    expect(screen.getByText(/20\.3/)).toBeInTheDocument();
    expect(screen.getByText(/30\.7/)).toBeInTheDocument();

    // Check voxel coordinates
    expect(screen.getByText(/50/)).toBeInTheDocument();
    expect(screen.getByText(/60/)).toBeInTheDocument();
    expect(screen.getByText(/70/)).toBeInTheDocument();
  });

  it('should update when crosshair changes via event', async () => {
    render(StatusBar);
    await waitFor(() => {});

    // Get the event handler that was registered
    const crosshairHandler = mockEventBus.on.mock.calls.find(
      call => call[0] === 'crosshair.changed'
    )?.[1];

    // Simulate crosshair change event
    if (crosshairHandler) {
      crosshairHandler({
        world: [15.0, 25.0, 35.0],
        voxel: [100, 110, 120]
      });
    }

    await waitFor(() => {
      expect(screen.getByText(/15\.0/)).toBeInTheDocument();
      expect(screen.getByText(/25\.0/)).toBeInTheDocument();
      expect(screen.getByText(/35\.0/)).toBeInTheDocument();
    });
  });

  it('should display intensity value when layer is active', async () => {
    // Set up layer state
    layerStoreState.activeLayerId = 'layer-1';
    layerStoreState.layers.set('layer-1', {
      id: 'layer-1',
      spec: { Volume: { id: 'layer-1', source_resource_id: 'volume-1' } }
    });

    // Mock intensity sampling
    mockLayerService.sampleWorldCoordinate.mockResolvedValue({ value: 123.45 });

    render(StatusBar);
    await waitFor(() => {});

    // Trigger sampling by changing crosshair
    crosshairStoreState.worldCoord = [5, 5, 5];
    crosshairStoreState.voxelCoord = [10, 10, 10];

    // Notify subscribers of the change
    const { useCrosshairStore } = await import('$lib/stores/crosshairSlice');
    const subscribers = (useCrosshairStore.subscribe as any).mock.calls;
    subscribers.forEach((call: any) => {
      const listener = call[0];
      listener(crosshairStoreState, crosshairStoreState);
    });

    await waitFor(() => {
      expect(screen.getByText(/123\.45/)).toBeInTheDocument();
    });
  });

  it('should show loading state while sampling', async () => {
    // Set up layer
    layerStoreState.activeLayerId = 'layer-1';
    layerStoreState.layers.set('layer-1', {
      id: 'layer-1',
      spec: { Volume: { id: 'layer-1', source_resource_id: 'volume-1' } }
    });

    // Mock slow sampling
    mockLayerService.sampleWorldCoordinate.mockImplementation(
      () => new Promise(resolve => setTimeout(() => resolve({ value: 100 }), 100))
    );

    render(StatusBar);
    await waitFor(() => {});

    // Trigger sampling
    crosshairStoreState.worldCoord = [1, 2, 3];

    // Notify subscribers
    const { useCrosshairStore } = await import('$lib/stores/crosshairSlice');
    const subscribers = (useCrosshairStore.subscribe as any).mock.calls;
    subscribers.forEach((call: any) => {
      const listener = call[0];
      listener(crosshairStoreState, crosshairStoreState);
    });

    // Should show loading state
    expect(screen.getByText('...')).toBeInTheDocument();

    // Wait for sampling to complete
    await waitFor(() => {
      expect(screen.queryByText('...')).not.toBeInTheDocument();
      expect(screen.getByText(/100/)).toBeInTheDocument();
    });
  });

  it('should handle sampling errors gracefully', async () => {
    // Set up layer
    layerStoreState.activeLayerId = 'layer-1';
    layerStoreState.layers.set('layer-1', {
      id: 'layer-1',
      spec: { Volume: { id: 'layer-1', source_resource_id: 'volume-1' } }
    });

    // Mock sampling error
    mockLayerService.sampleWorldCoordinate.mockRejectedValue(new Error('Sampling failed'));

    render(StatusBar);
    await waitFor(() => {});

    // Trigger sampling
    crosshairStoreState.worldCoord = [1, 2, 3];

    // Notify subscribers
    const { useCrosshairStore } = await import('$lib/stores/crosshairSlice');
    const subscribers = (useCrosshairStore.subscribe as any).mock.calls;
    subscribers.forEach((call: any) => {
      const listener = call[0];
      listener(crosshairStoreState, crosshairStoreState);
    });

    // Should show N/A on error
    await waitFor(() => {
      expect(screen.getByText('N/A')).toBeInTheDocument();
    });
  });

  it('should display mouse coordinates', async () => {
    render(StatusBar);
    await waitFor(() => {});

    // Get the event handler that was registered
    const mouseHandler = mockEventBus.on.mock.calls.find(
      call => call[0] === 'mouse.worldcoord'
    )?.[1];

    // Emit mouse coordinate event
    if (mouseHandler) {
      mouseHandler({ coord: { x: 50.5, y: 60.5, z: 70.5 } });
    }

    await waitFor(() => {
      expect(screen.getByText(/Mouse:/)).toBeInTheDocument();
      expect(screen.getByText(/50\.5/)).toBeInTheDocument();
      expect(screen.getByText(/60\.5/)).toBeInTheDocument();
      expect(screen.getByText(/70\.5/)).toBeInTheDocument();
    });
  });

  it('should handle responsive layout on small screens', async () => {
    // Mock small screen
    window.matchMedia = vi.fn().mockImplementation(query => ({
      matches: query === '(max-width: 640px)',
      media: query,
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
    }));

    render(StatusBar);
    await waitFor(() => {});

    // On small screens, abbreviations should be used
    expect(screen.getByText('W:')).toBeInTheDocument();
    expect(screen.getByText('V:')).toBeInTheDocument();
  });

  it('should clean up subscriptions on unmount', async () => {
    const { unmount } = render(StatusBar);
