/**
 * Tests for VolumeView Component
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, fireEvent, waitFor } from '@testing-library/svelte';
import VolumeView from './VolumeView.svelte';
import { mockService } from '@test-utils';
import { createMockContainer } from '@test-utils';
import { getEventBus } from '$lib/events/EventBus';
import { useLayerStore } from '$lib/stores/layerStore';
import type { LayerService } from '$lib/services/LayerService';
import type { VolumeService } from '$lib/services/VolumeService';
import type { NotificationService } from '$lib/services/NotificationService';
import type { Layer } from '$lib/stores/layerStore';
import { nanoid } from 'nanoid';

// Mock OrthogonalViewGPU component
vi.mock('./OrthogonalViewGPU.svelte', () => ({
  default: {
    render: () => ({
      component: {
        $$: {
          fragment: {
            c: () => {},
            m: () => {},
            p: () => {},
            d: () => {}
          }
        }
      }
    })
  }
}));

// Mock nanoid
vi.mock('nanoid', () => ({
  nanoid: vi.fn(() => 'test-id')
}));

describe('VolumeView', () => {
  let layerService: LayerService;
  let volumeService: VolumeService;
  let notificationService: NotificationService;
  let eventBus: ReturnType<typeof getEventBus>;
  let glContainer: any;

  // Mock layer data
  const mockLayer: Layer = {
    id: 'layer-1',
    spec: {
      Volume: {
        id: 'vol-1',
        source_resource_id: 'volume-1',
        colormap: 'grayscale',
        slice_axis: null,
        slice_index: null
      }
    },
    gpu: {
      textureId: 'tex-1',
      renderTargetId: 'rt-1',
      dataRange: { min: 0, max: 255 },
      dimensions: { width: 256, height: 256, depth: 128 }
    }
  };

  beforeEach(() => {
    // Clear stores
    useLayerStore.setState({ layers: [], activeLayerId: null });

    // Setup event bus
    eventBus = getEventBus();

    // Mock services
    layerService = mockService<LayerService>({
      addLayer: vi.fn().mockResolvedValue('new-layer-id'),
      removeLayer: vi.fn().mockResolvedValue(undefined),
      updateLayer: vi.fn().mockResolvedValue(undefined)
    });

    volumeService = mockService<VolumeService>({
      loadVolume: vi.fn().mockResolvedValue('volume-id-123'),
      unloadVolume: vi.fn().mockResolvedValue(undefined)
    });

    notificationService = mockService<NotificationService>({
      success: vi.fn(),
      error: vi.fn(),
      warning: vi.fn()
    });

    // Mock DI container
    vi.doMock('$lib/di/Container', () => ({
      getService: vi.fn().mockImplementation((name: string) => {
        switch (name) {
          case 'layerService': return Promise.resolve(layerService);
          case 'volumeService': return Promise.resolve(volumeService);
          case 'notificationService': return Promise.resolve(notificationService);
          default: return Promise.reject(new Error(`Unknown service: ${name}`));
        }
      })
    }));

    // Create mock GoldenLayout container
    glContainer = createMockContainer();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe('Initial state', () => {
    it('should show empty state when no layers exist', async () => {
      const { getByText } = render(VolumeView);

      await waitFor(() => {
        expect(getByText('No volume loaded')).toBeInTheDocument();
        expect(getByText('Double-click a file or drag it here')).toBeInTheDocument();
      });
    });

    it('should auto-select first layer if available', async () => {
      // Add layer to store
      useLayerStore.setState({ layers: [mockLayer] });

      const { container } = render(VolumeView);

      await waitFor(() => {
