/**
 * Tests for FileBrowserPanel Component
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, waitFor } from '@testing-library/svelte';
import { mockService } from '@test-utils';
import { getEventBus } from '$lib/events/EventBus';
import type { VolumeService } from '$lib/services/VolumeService';
import type { LayerService } from '$lib/services/LayerService';
import type { ConfigService } from '$lib/services/ConfigService';
import type { NotificationService } from '$lib/services/NotificationService';

// Mock dependencies
vi.mock('../MountableTreeBrowser.svelte');
vi.mock('nanoid', () => ({
  nanoid: vi.fn(() => 'test-id')
}));

// Mock the DI container
let mockGetService: any;
vi.mock('$lib/di/Container', () => ({
  getService: vi.fn(async (name: string) => mockGetService(name))
}));

// Import component after mocks
import FileBrowserPanel from './FileBrowserPanel.svelte';

describe('FileBrowserPanel', () => {
  let volumeService: VolumeService;
  let layerService: LayerService;
  let configService: ConfigService;
  let notificationService: NotificationService;
  let eventBus: ReturnType<typeof getEventBus>;

  beforeEach(() => {
    eventBus = getEventBus();
    vi.clearAllMocks();

    // Mock services
    volumeService = mockService<VolumeService>({
      loadVolume: vi.fn().mockResolvedValue('volume-123')
    });

    layerService = mockService<LayerService>({
      addLayer: vi.fn().mockResolvedValue('layer-123'),
      requestGpuResources: vi.fn().mockResolvedValue(undefined),
      setActiveLayer: vi.fn()
    });

    configService = mockService<ConfigService>({
      get: vi.fn().mockImplementation((key, defaultValue) => {
        if (key === 'brainflow-recent-files') return [];
        if (key === 'filebrowser.autoCreateLayers') return true;
        if (key === 'filebrowser.defaultColormap') return 'grayscale';
        return defaultValue;
      }),
      set: vi.fn().mockResolvedValue(undefined)
    });

    notificationService = mockService<NotificationService>({
      success: vi.fn(),
      error: vi.fn(),
      warning: vi.fn(),
      info: vi.fn()
    });

    // Set up DI container mock
    mockGetService = (name: string) => {
      switch (name) {
        case 'volumeService': return Promise.resolve(volumeService);
        case 'layerService': return Promise.resolve(layerService);
        case 'configService': return Promise.resolve(configService);
        case 'notificationService': return Promise.resolve(notificationService);
        default: return Promise.reject(new Error(`Unknown service: ${name}`));
      }
    };
  });

  it('should render and initialize', async () => {
    const { container } = render(FileBrowserPanel);

    await waitFor(() => {
      expect(container).toBeTruthy();
      expect(configService.get).toHaveBeenCalledWith('brainflow-recent-files', []);
    });
  });

  it('should emit ready event after initialization', async () => {
    const readySpy = vi.fn();
    eventBus.on('filebrowser.ready', readySpy);

    render(FileBrowserPanel);

    await waitFor(() => {
      expect(readySpy).toHaveBeenCalled();
    });
  });

  it('should handle file selection event', async () => {
    render(FileBrowserPanel);

    // Emit file selected event
    eventBus.emit('filebrowser.file.selected', {
      file: {
        id: '/test/file.nii',
        name: 'file.nii',
        is_dir: false
      }
    });

    await waitFor(() => {
      expect(volumeService.loadVolume).toHaveBeenCalledWith('/test/file.nii');
    });
  });
});

