/**
 * Central export point for all test utilities
 */

// Setup
export * from './setup/vitest-setup';

// Mocks
export { createMockEventBus, waitForEvent, assertEventSequence, assertEventEmitted } from './mocks/mockEventBus';
export { mockService, createAsyncMockService, mockResolvedValue, mockRejectedValue, mockSequence, mockAsyncSequence } from './mocks/mockService';
export { createMockDIContainer, setupMockServices, createTestContext } from './mocks/mockDI';
export { createMockStore, createMockSvelteStore, createMockLayerStore, createMockCrosshairStore, createMockVolumeStore, spyOnStore } from './mocks/mockStores';

// Helpers
export { renderComponent, waitForUpdates, renderAndWait, waitFor, flushPromises } from './helpers/render';

// Re-export commonly used testing library functions
export { cleanup, fireEvent, screen, within } from '@testing-library/svelte';
export { describe, it, expect, vi, beforeEach, afterEach, beforeAll, afterAll } from 'vitest';

import { defineConfig } from 'vitest/config';
import { sveltekit } from '@sveltejs/kit/vite';
import path from 'path';

export default defineConfig({
  plugins: [sveltekit()],
  test: {
    include: ['src/**/*.{test,spec}.{js,ts}'],
    environment: 'jsdom',
    setupFiles: ['./src/test-utils/setup/vitest-setup.ts'],
    globals: true,
    // Aggressive mock cleanup
    clearMocks: true,     // resets call/return tracking
    restoreMocks: true,   // restores spied properties
    mockReset: true,      // reset mock state between tests
    // Pool configuration to manage memory and isolation
    pool: 'threads',
    poolOptions: {
      threads: {
        singleThread: false, // Allow parallel execution
        isolate: true, // Isolate each test file
        minThreads: 1,
        maxThreads: 4 // Limit concurrent threads to prevent resource exhaustion
      }
    },
    // Memory management settings
    testTimeout: 30000,
    teardownTimeout: 10000,
    coverage: {
      reporter: ['text', 'json', 'html'],
      exclude: [
        'node_modules/',
        'src/**/*.d.ts',
        '**/*.config.*',
        '**/__tests__/**',
        'src/app.html',
        'src/test-utils/**',
        'src/test-examples/**'
      ]
    }
  },
  resolve: {
    conditions: ['browser'],
    alias: {
      '$lib': path.resolve('./src/lib'),
      '@test-utils': path.resolve('./src/test-utils')
    }
  }
});

