/**
 * Tests for VolumeView Component
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, fireEvent, waitFor } from '@testing-library/svelte';
import VolumeView from './VolumeView.svelte';
import { mockService } from '@test-utils';
import { createMockContainer } from '@test-utils';
import { getEventBus } from '$lib/events/EventBus';
import { useLayerStore } from '$lib/stores/layerStore';
import type { LayerService } from '$lib/services/LayerService';
import type { VolumeService } from '$lib/services/VolumeService';
import type { NotificationService } from '$lib/services/NotificationService';
import type { Layer } from '$lib/stores/layerStore';
import { nanoid } from 'nanoid';

// Mock OrthogonalViewGPU component
vi.mock('./OrthogonalViewGPU.svelte', () => ({
  default: {
    render: () => ({
      component: {
        $$: {
          fragment: {
            c: () => {},
            m: () => {},
            p: () => {},
            d: () => {}
          }
        }
      }
    })
  }
}));

// Mock nanoid
vi.mock('nanoid', () => ({
  nanoid: vi.fn(() => 'test-id')
}));

describe('VolumeView', () => {
  let layerService: LayerService;
  let volumeService: VolumeService;
  let notificationService: NotificationService;
  let eventBus: ReturnType<typeof getEventBus>;
  let glContainer: any;

  // Mock layer data
  const mockLayer: Layer = {
    id: 'layer-1',
    spec: {
      Volume: {
        id: 'vol-1',
        source_resource_id: 'volume-1',
        colormap: 'grayscale',
        slice_axis: null,
        slice_index: null
      }
    },
    gpu: {
      textureId: 'tex-1',
      renderTargetId: 'rt-1',
      dataRange: { min: 0, max: 255 },
      dimensions: { width: 256, height: 256, depth: 128 }
    }
  };

  beforeEach(() => {
    // Clear stores
    useLayerStore.setState({ layers: [], activeLayerId: null });

    // Setup event bus
    eventBus = getEventBus();

    // Mock services
    layerService = mockService<LayerService>({
      addLayer: vi.fn().mockResolvedValue('new-layer-id'),
      removeLayer: vi.fn().mockResolvedValue(undefined),
      updateLayer: vi.fn().mockResolvedValue(undefined)
    });

    volumeService = mockService<VolumeService>({
      loadVolume: vi.fn().mockResolvedValue('volume-id-123'),
      unloadVolume: vi.fn().mockResolvedValue(undefined)
    });

    notificationService = mockService<NotificationService>({
      success: vi.fn(),
      error: vi.fn(),
      warning: vi.fn()
    });

    // Mock DI container
    vi.doMock('$lib/di/Container', () => ({
      getService: vi.fn().mockImplementation((name: string) => {
        switch (name) {
          case 'layerService': return Promise.resolve(layerService);
          case 'volumeService': return Promise.resolve(volumeService);
          case 'notificationService': return Promise.resolve(notificationService);
          default: return Promise.reject(new Error(`Unknown service: ${name}`));
        }
      })
    }));

    // Create mock GoldenLayout container
    glContainer = createMockContainer();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe('Initial state', () => {
    it('should show empty state when no layers exist', async () => {
      const { getByText } = render(VolumeView);

      await waitFor(() => {
        expect(getByText('No volume loaded')).toBeInTheDocument();
        expect(getByText('Double-click a file or drag it here')).toBeInTheDocument();
      });
    });

    it('should auto-select first layer if available', async () => {
      // Add layer to store
      useLayerStore.setState({ layers: [mockLayer] });

      const { container } = render(VolumeView);

      await waitFor(() => {
        // Should render orthogonal views
        expect(container.querySelector('.orthogonal-views')).toBeInTheDocument();
      });
    });

    it('should use initial state from props', async () => {
      useLayerStore.setState({ layers: [mockLayer] });

      const { container } = render(VolumeView, {
        props: {
          initialState: { layerId: 'layer-1' }
        }
      });

      await waitFor(() => {
        expect(container.querySelector('.orthogonal-views')).toBeInTheDocument();
      });
    });

    it('should use component state over initial state', async () => {
      useLayerStore.setState({ 
        layers: [
          mockLayer,
          { ...mockLayer, id: 'layer-2' }
        ] 
      });

      const { container } = render(VolumeView, {
        props: {
          initialState: { layerId: 'layer-1' },
          componentState: { layerId: 'layer-2' }
        }
      });

      await waitFor(() => {
        expect(container.querySelector('.orthogonal-views')).toBeInTheDocument();
      });
    });
  });

  describe('Layer selection', () => {
    it('should emit event when layer is selected', async () => {
      const eventSpy = vi.fn();
      eventBus.on('volumeview.layer.selected', eventSpy);

      useLayerStore.setState({ layers: [mockLayer] });

      render(VolumeView);

      await waitFor(() => {
        expect(eventSpy).toHaveBeenCalledWith({ layerId: 'layer-1' });
      });
    });

    it('should update GoldenLayout state when layer is selected', async () => {
      useLayerStore.setState({ layers: [mockLayer] });

      render(VolumeView, {
        props: { glContainer }
      });

      await waitFor(() => {
        expect(glContainer.setState).toHaveBeenCalledWith({ layerId: 'layer-1' });
        expect(glContainer.setTitle).toHaveBeenCalledWith('Volume View - vol-1');
      });
    });

    it('should respond to external layer selection', async () => {
      useLayerStore.setState({ 
        layers: [
          mockLayer,
          { ...mockLayer, id: 'layer-2' }
        ] 
      });

      const { container } = render(VolumeView);

      await waitFor(() => {
        expect(container.querySelector('.orthogonal-views')).toBeInTheDocument();
      });

      // Emit external selection event
      eventBus.emit('layer.selected', { layerId: 'layer-2' });

      await waitFor(() => {
        // Component should update to show layer-2
        expect(container.querySelector('.orthogonal-views')).toBeInTheDocument();
      });
    });
  });

  describe('Drag and drop', () => {
    it('should handle file drop', async () => {
      const { container } = render(VolumeView);
      const dropZone = container.querySelector('.volume-view-container')!;

      // Create drag event with file data
      const dropEvent = new Event('drop', { bubbles: true }) as any;
      dropEvent.preventDefault = vi.fn();
      dropEvent.dataTransfer = {
        getData: vi.fn((type) => {
          if (type === 'application/x-brainflow-file') {
            return JSON.stringify({ path: '/test/file.nii', name: 'test.nii' });
          }
          return '';
        })
      };

      fireEvent(dropZone, dropEvent);

      await waitFor(() => {
        expect(volumeService.loadVolume).toHaveBeenCalledWith('/test/file.nii');
        expect(layerService.addLayer).toHaveBeenCalled();
        expect(notificationService.success).toHaveBeenCalledWith('Loaded test.nii');
      });
    });

    it('should show drag over state', async () => {
      const { container } = render(VolumeView);
      const dropZone = container.querySelector('.volume-view-container')!;

      // Simulate drag over
      const dragOverEvent = new Event('dragover', { bubbles: true }) as any;
      dragOverEvent.preventDefault = vi.fn();
      dragOverEvent.dataTransfer = { dropEffect: '' };

      fireEvent(dropZone, dragOverEvent);

      expect(dropZone).toHaveClass('drag-over');

      // Simulate drag leave
      const dragLeaveEvent = new Event('dragleave', { bubbles: true }) as any;
      dragLeaveEvent.preventDefault = vi.fn();

      fireEvent(dropZone, dragLeaveEvent);

      expect(dropZone).not.toHaveClass('drag-over');
    });

    it('should handle drop errors', async () => {
      volumeService.loadVolume = vi.fn().mockRejectedValue(new Error('Load failed'));

      const { container } = render(VolumeView);
      const dropZone = container.querySelector('.volume-view-container')!;

      const dropEvent = new Event('drop', { bubbles: true }) as any;
      dropEvent.preventDefault = vi.fn();
      dropEvent.dataTransfer = {
        getData: vi.fn(() => JSON.stringify({ path: '/test/file.nii', name: 'test.nii' }))
      };

      fireEvent(dropZone, dropEvent);

      await waitFor(() => {
        expect(notificationService.error).toHaveBeenCalledWith(
          'Failed to load file',
          expect.objectContaining({ error: expect.any(Error) })
        );
      });
    });
  });

  describe('Layer events', () => {
    it('should select new layer when added', async () => {
      render(VolumeView);

      // Add layer to store
      useLayerStore.setState({ layers: [mockLayer] });

      // Emit layer added event
      eventBus.emit('layer.added', { layerId: 'layer-1' });

      await waitFor(() => {
        const state = useLayerStore.getState();
        expect(state.layers).toHaveLength(1);
      });
    });

    it('should handle layer removal', async () => {
      useLayerStore.setState({ layers: [mockLayer] });

      render(VolumeView, {
        props: { glContainer }
      });

      await waitFor(() => {
        expect(glContainer.setTitle).toHaveBeenCalledWith('Volume View - vol-1');
      });

      // Remove the layer
      useLayerStore.setState({ layers: [] });
      eventBus.emit('layer.removed', { layerId: 'layer-1' });

      await waitFor(() => {
        expect(glContainer.setTitle).toHaveBeenCalledWith('Volume View');
      });
    });

    it('should select next layer when current is removed', async () => {
      const layer2 = { ...mockLayer, id: 'layer-2' };
      useLayerStore.setState({ layers: [mockLayer, layer2] });

      const eventSpy = vi.fn();
      eventBus.on('volumeview.layer.selected', eventSpy);

      render(VolumeView);

      // Remove first layer
      useLayerStore.setState({ layers: [layer2] });
      eventBus.emit('layer.removed', { layerId: 'layer-1' });

      await waitFor(() => {
        expect(eventSpy).toHaveBeenCalledWith({ layerId: 'layer-2' });
      });
    });
  });

  describe('Loading states', () => {
    it('should show loading state during file drop', async () => {
      // Make loadVolume slow
      volumeService.loadVolume = vi.fn(() => new Promise(resolve => setTimeout(() => resolve('volume-id'), 100)));

      const { container, getByText } = render(VolumeView);
      const dropZone = container.querySelector('.volume-view-container')!;

      const dropEvent = new Event('drop', { bubbles: true }) as any;
      dropEvent.preventDefault = vi.fn();
      dropEvent.dataTransfer = {
        getData: vi.fn(() => JSON.stringify({ path: '/test/file.nii', name: 'test.nii' }))
      };

      fireEvent(dropZone, dropEvent);

      // Should show loading immediately
      expect(getByText('Loading volume...')).toBeInTheDocument();

      // Wait for load to complete
      await waitFor(() => {
        expect(notificationService.success).toHaveBeenCalled();
      });
    });

    it('should show GPU preparation state', async () => {
      // Layer without GPU resources
      const layerNoGpu = { ...mockLayer, gpu: null };
      useLayerStore.setState({ layers: [layerNoGpu] });

      const { getByText } = render(VolumeView);

      await waitFor(() => {
        expect(getByText('Preparing GPU resources...')).toBeInTheDocument();
      });
    });
  });

  describe('Error handling', () => {
    it('should display initialization errors', async () => {
      // Make service resolution fail
      vi.doMock('$lib/di/Container', () => ({
        getService: vi.fn().mockRejectedValue(new Error('Service not found'))
      }));

      const { getByText } = render(VolumeView);

      await waitFor(() => {
        expect(getByText(/Error: Failed to initialize/)).toBeInTheDocument();
      });
    });

    it('should display error state from drop failure', async () => {
      volumeService.loadVolume = vi.fn().mockRejectedValue(new Error('Test error message'));

      const { container, getByText } = render(VolumeView);
      const dropZone = container.querySelector('.volume-view-container')!;

      const dropEvent = new Event('drop', { bubbles: true }) as any;
      dropEvent.preventDefault = vi.fn();
      dropEvent.dataTransfer = {
        getData: vi.fn(() => JSON.stringify({ path: '/test/file.nii', name: 'test.nii' }))
      };

      fireEvent(dropZone, dropEvent);

      await waitFor(() => {
        expect(getByText(/Error: Test error message/)).toBeInTheDocument();
      });
    });
  });

  describe('Viewport events', () => {
    it('should emit viewport change events', async () => {
      useLayerStore.setState({ layers: [mockLayer] });

      const eventSpy = vi.fn();
      eventBus.on('volumeview.viewport.changed', eventSpy);

      const { component } = render(VolumeView);

      // Call the viewport change handler
      const viewportData = { scale: 2, offset: [10, 20] as [number, number] };
      component.handleViewportChange('axial', viewportData);

      expect(eventSpy).toHaveBeenCalledWith({
        viewType: 'axial',
        viewport: viewportData
      });
    });
  });

  describe('GoldenLayout integration', () => {
    it('should update state when container state changes', async () => {
      useLayerStore.setState({ layers: [mockLayer] });

      render(VolumeView, {
        props: { glContainer }
      });

      // Simulate GoldenLayout state change
      const newState = { layerId: 'layer-1' };
      glContainer.getState.mockReturnValue(newState);

      // Trigger the state changed handler
      const stateChangedHandler = glContainer.on.mock.calls.find(
        call => call[0] === 'stateChanged'
      )?.[1];

      if (stateChangedHandler) {
        stateChangedHandler();
      }

      await waitFor(() => {
        expect(glContainer.setState).toHaveBeenCalled();
      });
    });

    it('should provide updateLayerId method', async () => {
      useLayerStore.setState({ layers: [mockLayer] });

      render(VolumeView, {
        props: { glContainer }
      });

      await waitFor(() => {
        expect(glContainer.updateLayerId).toBeDefined();
      });

      // Call the update method
      glContainer.updateLayerId('layer-1');

      expect(glContainer.setState).toHaveBeenCalledWith({ layerId: 'layer-1' });
    });
  });

  describe('Cleanup', () => {
    it('should clean up subscriptions on unmount', async () => {
      const { unmount } = render(VolumeView);

      // Get the cleanup functions
      const unsubscribeSpy = vi.fn();
      eventBus.on = vi.fn(() => unsubscribeSpy);

      await waitFor(() => {
        // Component should be mounted
        expect(document.querySelector('.volume-view-container')).toBeInTheDocument();
      });

      unmount();

      // Verify cleanup happened (indirectly through store state)
      expect(useLayerStore.getState().layers).toEqual([]);
    });
  });
});

