/**
 * TreeBrowser Component Tests
 * Tests for the migrated TreeBrowser component using the new architecture
 */
import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import TreeBrowser from './TreeBrowser.svelte';
import { createMockDIContainer, setupMockServices } from '@test-utils';
import { createMockEventBus } from '@test-utils';
import { createMockStore } from '@test-utils';
import { flushPromises } from '@test-utils';
import type { FlatNode } from '@brainflow/api';

// Mock the DI container
vi.mock('$lib/di/Container', () => ({
  getService: vi.fn()
}));

// Mock the stores
vi.mock('$lib/stores/mountStore', () => ({
  mountStore: {
    subscribe: vi.fn(),
    getState: vi.fn(),
    setActiveMount: vi.fn()
  }
}));

describe('TreeBrowser', () => {
  let container: ReturnType<typeof createMockDIContainer>;
  let eventBus: ReturnType<typeof createMockEventBus>;
  let mountStore: ReturnType<typeof createMockStore>;
  let getService: any;
  let mockMountService: any;

  const mockNodes: FlatNode[] = [
    {
      name: 'data',
      path: '/data',
      children: ['sub1', 'file1.nii'],
      node_type: 'DIRECTORY',
      resource_type: null,
      size: null,
      last_modified: null
    },
    {
      name: 'sub1',
      path: '/data/sub1',
      children: ['anat'],
      node_type: 'DIRECTORY',
      resource_type: null,
      size: null,
      last_modified: null
    },
    {
      name: 'anat',
      path: '/data/sub1/anat',
      children: ['T1w.nii.gz'],
      node_type: 'DIRECTORY',
      resource_type: null,
      size: null,
      last_modified: null
    },
    {
      name: 'T1w.nii.gz',
      path: '/data/sub1/anat/T1w.nii.gz',
      children: [],
      node_type: 'FILE',
      resource_type: 'Volume',
      size: 1024000,
      last_modified: '2024-01-01T00:00:00Z'
    },
    {
      name: 'file1.nii',
      path: '/data/file1.nii',
      children: [],
      node_type: 'FILE',
      resource_type: 'Volume',
      size: 512000,
      last_modified: '2024-01-01T00:00:00Z'
    }
  ];

  beforeEach(() => {
    // Set up mocks
    container = createMockDIContainer();
    eventBus = createMockEventBus();
    const services = setupMockServices(container);

    // Create mock mount store
    mountStore = createMockStore({
      activeMount: 'local',
      mounts: new Map([
        ['local', { id: 'local', path: '/data', label: 'Local Data' }]
      ]),
      setActiveMount: vi.fn()
    });

    // Mock mount service
    mockMountService = {
      scanDirectory: vi.fn().mockResolvedValue(mockNodes),
      loadFile: vi.fn().mockResolvedValue('volume-id'),
      getMountInfo: vi.fn().mockReturnValue({ id: 'local', path: '/data', label: 'Local Data' })
    };

    // Mock store implementations
    const { mountStore: mockMountStore } = require('$lib/stores/mountStore');
    mockMountStore.subscribe.mockImplementation(mountStore.subscribe);
    mockMountStore.getState.mockImplementation(mountStore.getState);
    mockMountStore.setActiveMount.mockImplementation((id: string) => {
      mountStore.setState({ activeMount: id });
    });

    // Set up DI container mock
    getService = require('$lib/di/Container').getService;
    getService.mockImplementation(async (name: string) => {
      switch (name) {
        case 'mountService':
          return mockMountService;
        case 'volumeService':
          return services.mockApi;
        case 'notificationService':
          return services.mockNotificationService;
        case 'eventBus':
          return eventBus;
        default:
          return container.get(name);
      }
    });
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should render with initial loading state', async () => {
    render(TreeBrowser);

    expect(screen.getByTestId('tree-loading')).toBeInTheDocument();

    await waitFor(() => {
      expect(screen.queryByTestId('tree-loading')).not.toBeInTheDocument();
    });
  });

  it('should display tree nodes after loading', async () => {
    render(TreeBrowser);
    await flushPromises();

    // Check root directory is displayed
    expect(screen.getByText('data')).toBeInTheDocument();
    expect(screen.getByTestId('node-/data')).toBeInTheDocument();
  });

  it('should expand/collapse directories on click', async () => {
    render(TreeBrowser);
    await flushPromises();

    const dataNode = screen.getByTestId('node-/data');
    const expandButton = dataNode.querySelector('[data-testid="expand-button"]');

    // Initially collapsed
    expect(screen.queryByText('sub1')).not.toBeInTheDocument();
    expect(screen.queryByText('file1.nii')).not.toBeInTheDocument();

    // Click to expand
    fireEvent.click(expandButton!);
    await flushPromises();

    // Should show children
    expect(screen.getByText('sub1')).toBeInTheDocument();
    expect(screen.getByText('file1.nii')).toBeInTheDocument();

    // Click to collapse
    fireEvent.click(expandButton!);
    await flushPromises();

    // Should hide children
    expect(screen.queryByText('sub1')).not.toBeInTheDocument();
    expect(screen.queryByText('file1.nii')).not.toBeInTheDocument();
  });

  it('should load file on double-click', async () => {
    render(TreeBrowser);
    await flushPromises();

    // Expand to show file
    const dataNode = screen.getByTestId('node-/data');
    fireEvent.click(dataNode.querySelector('[data-testid="expand-button"]')!);
    await flushPromises();

    // Double-click file
    const fileNode = screen.getByTestId('node-/data/file1.nii');
    fireEvent.dblClick(fileNode);

    await waitFor(() => {
      expect(mockMountService.loadFile).toHaveBeenCalledWith('/data/file1.nii');
      expect(eventBus.emit).toHaveBeenCalledWith('file.loaded', {
        path: '/data/file1.nii',
        volumeId: 'volume-id'
      });
    });
  });

  it('should show context menu on right-click', async () => {
    render(TreeBrowser);
    await flushPromises();

    const dataNode = screen.getByTestId('node-/data');
    fireEvent.contextMenu(dataNode);

    await waitFor(() => {
      expect(screen.getByText('Open')).toBeInTheDocument();
      expect(screen.getByText('Copy Path')).toBeInTheDocument();
      expect(screen.getByText('Show in Finder')).toBeInTheDocument();
    });
  });

  it('should handle file loading errors', async () => {
    mockMountService.loadFile.mockRejectedValueOnce(new Error('Failed to load'));

    render(TreeBrowser);
    await flushPromises();

    // Expand and double-click file
    const dataNode = screen.getByTestId('node-/data');
    fireEvent.click(dataNode.querySelector('[data-testid="expand-button"]')!);
    await flushPromises();

    const fileNode = screen.getByTestId('node-/data/file1.nii');
    fireEvent.dblClick(fileNode);

    await waitFor(() => {
      expect(container.get('notificationService').error).toHaveBeenCalledWith(
        'Failed to load file',
        expect.objectContaining({ error: expect.any(Error) })
      );
    });
  });

  it('should filter nodes based on search input', async () => {
    render(TreeBrowser);
    await flushPromises();

    // Expand all nodes
    const dataNode = screen.getByTestId('node-/data');
    fireEvent.click(dataNode.querySelector('[data-testid="expand-button"]')!);
    await flushPromises();

    // Search for "T1w"
    const searchInput = screen.getByPlaceholderText('Search files...');
    fireEvent.input(searchInput, { target: { value: 'T1w' } });
    await waitFor(() => {}, { timeout: 350 }); // Wait for debounce

    // Should only show matching file and its parents
    expect(screen.getByText('data')).toBeInTheDocument();
    expect(screen.getByText('sub1')).toBeInTheDocument();
    expect(screen.getByText('anat')).toBeInTheDocument();
    expect(screen.getByText('T1w.nii.gz')).toBeInTheDocument();
    expect(screen.queryByText('file1.nii')).not.toBeInTheDocument();
  });

  it('should refresh tree on mount change', async () => {
    render(TreeBrowser);
    await flushPromises();

    // Change active mount
    mountStore.setState({ activeMount: 'remote' });

    // Emit mount change event
    eventBus.emit('mount.changed', { mountId: 'remote' });

    await waitFor(() => {
      expect(mockMountService.scanDirectory).toHaveBeenCalledTimes(2);
    });
  });

  it('should handle keyboard navigation', async () => {
    render(TreeBrowser);
    await flushPromises();

    const tree = screen.getByRole('tree');
    const dataNode = screen.getByTestId('node-/data');

    // Focus on tree
    fireEvent.focus(tree);

    // Press Enter to expand
    fireEvent.keyDown(tree, { key: 'Enter' });
    await flushPromises();

    expect(screen.getByText('sub1')).toBeInTheDocument();

    // Press arrow down to navigate
    fireEvent.keyDown(tree, { key: 'ArrowDown' });
    await flushPromises();

    // Check focus moved (would need to implement proper focus tracking)
    // This is a simplified test
    expect(document.activeElement).toBeTruthy();
  });

  it('should display file metadata in tooltip', async () => {
    render(TreeBrowser);
    await flushPromises();

    // Expand to show file
    const dataNode = screen.getByTestId('node-/data');
    fireEvent.click(dataNode.querySelector('[data-testid="expand-button"]')!);
    await flushPromises();

    const fileNode = screen.getByTestId('node-/data/file1.nii');

    // Hover to show tooltip
    fireEvent.mouseEnter(fileNode);

    await waitFor(() => {
      expect(screen.getByText(/Size: 500\.0 KB/)).toBeInTheDocument();
      expect(screen.getByText(/Modified:/)).toBeInTheDocument();
    });
  });

  it('should handle mount switching', async () => {
    // Add another mount
    mountStore.setState({
      mounts: new Map([
        ['local', { id: 'local', path: '/data', label: 'Local Data' }],
        ['remote', { id: 'remote', path: '/remote', label: 'Remote Data' }]
      ])
    });

    render(TreeBrowser);
    await flushPromises();

    // Should show mount selector
    const mountSelector = screen.getByRole('combobox');
    expect(mountSelector).toBeInTheDocument();

    // Change mount
    fireEvent.change(mountSelector, { target: { value: 'remote' } });

    await waitFor(() => {
      expect(mountStore.getState().setActiveMount).toHaveBeenCalledWith('remote');
      expect(mockMountService.scanDirectory).toHaveBeenCalled();
    });
  });

  it('should clean up subscriptions on unmount', async () => {
    const { unmount } = render(TreeBrowser);
    await flushPromises();

    // Get unsubscribe functions
    const unsubscribes = eventBus.on.mock.calls.map(call => call[1]);

    // Unmount
    unmount();

    // Verify event listeners were cleaned up
    expect(eventBus.getListenerCount('mount.changed')).toBe(0);
    expect(eventBus.getListenerCount('file.request.load')).toBe(0);
  });
});

describe('TreeBrowser - Accessibility', () => {
  let container: ReturnType<typeof createMockDIContainer>;

  beforeEach(() => {
    container = createMockDIContainer();
    setupMockServices(container);

    const getService = require('$lib/di/Container').getService;
    getService.mockImplementation((name: string) => container.get(name));
  });

  it('should have proper ARIA attributes', async () => {
    render(TreeBrowser);
    await flushPromises();

    const tree = screen.getByRole('tree');
    expect(tree).toHaveAttribute('aria-label', 'File browser');

    const treeItems = screen.getAllByRole('treeitem');
    expect(treeItems.length).toBeGreaterThan(0);

    treeItems.forEach(item => {
      expect(item).toHaveAttribute('aria-expanded');
      expect(item).toHaveAttribute('aria-level');
    });
  });

  it('should announce selection changes', async () => {
    render(TreeBrowser);
    await flushPromises();

    const dataNode = screen.getByTestId('node-/data');

    // Click to select
    fireEvent.click(dataNode);

    // Should have aria-selected
    expect(dataNode).toHaveAttribute('aria-selected', 'true');
  });
});

