     1→/**
     2→ * Mock Dependency Injection Container
     3→ * Provides test-friendly DI container for isolating services
     4→ */
     5→import { vi } from 'vitest';
     6→import type { DIContainer, ServiceFactory } from '$lib/di/Container';
     7→
     8→export interface MockDIContainer extends DIContainer {
     9→  // Test helpers
    10→  getRegisteredServices(): string[];
    11→  hasService(name: string): boolean;
    12→  clearAll(): void;
    13→  registerMock<T>(name: string, mockInstance: T): void;
    14→}
    15→
    16→/**
    17→ * Creates a mock DI container for testing
    18→ */
    19→export function createMockDIContainer(): MockDIContainer {
    20→  const services = new Map<string, any>();
    21→  const factories = new Map<string, ServiceFactory<any>>();
    22→  const resolving = new Set<string>();
    23→  
    24→  const register = vi.fn(<T>(name: string, factory: ServiceFactory<T>) => {
    25→    factories.set(name, factory);
    26→  });
    27→  
    28→  const get = vi.fn(async <T>(name: string): Promise<T> => {
    29→    // Return mock if registered
    30→    if (services.has(name)) {
    31→      return services.get(name);
    32→    }
    33→    
    34→    // Check for circular dependency
    35→    if (resolving.has(name)) {
    36→      throw new Error(`Circular dependency detected: ${name}`);
    37→    }
    38→    
    39→    // Get factory
    40→    const factory = factories.get(name);
    41→    if (!factory) {
    42→      throw new Error(`Service not registered: ${name}`);
    43→    }
    44→    
    45→    // Resolve service
    46→    resolving.add(name);
    47→    try {
    48→      const service = await factory(container);
    49→      services.set(name, service);
    50→      return service;
    51→    } finally {
    52→      resolving.delete(name);
    53→    }
    54→  });
    55→  
    56→  const has = vi.fn((name: string): boolean => {
    57→    return factories.has(name) || services.has(name);
    58→  });
    59→  
    60→  const clear = vi.fn(() => {
    61→    services.clear();
    62→    factories.clear();
    63→    resolving.clear();
    64→  });
    65→  
    66→  // Test helpers
    67→  const getRegisteredServices = () => {
    68→    const serviceNames = new Set([
    69→      ...Array.from(services.keys()),
    70→      ...Array.from(factories.keys())
    71→    ]);
    72→    return Array.from(serviceNames);
    73→  };
    74→  
    75→  const hasService = (name: string) => has(name);
    76→  
    77→  const clearAll = () => clear();
    78→  
    79→  const registerMock = <T>(name: string, mockInstance: T) => {
    80→    services.set(name, mockInstance);
    81→  };
    82→  
    83→  const container: MockDIContainer = {
    84→    register,
    85→    get,
    86→    has,
    87→    clear,
    88→    getRegisteredServices,
    89→    hasService,
    90→    clearAll,
    91→    registerMock
    92→  };
    93→  
    94→  return container;
    95→}
    96→
    97→/**
    98→ * Helper to set up common mocked services
    99→ */
   100→export function setupMockServices(container: MockDIContainer) {
   101→  // Mock API
   102→  const mockApi = {
   103→    load_file: vi.fn().mockResolvedValue('mock-volume-id'),
